mapper.select:
select e.*, k.name as knowledge_point_name from exercise e left join knowledge_point k on e.knowledge_point_id = k.id
and e.title like concat('%', #{title}, '%') and e.difficulty = #{difficulty} and e.subject = #{subject}
order by e.id desc

mapper.update:
update exercise set title=#{title}, content=#{content}, difficulty=#{difficulty}, knowledge_point_id=#{knowledgePointId}, file_url=#{fileUrl}, subject=#{subject},
option_a=#{optionA}, option_b=#{optionB}, option_c=#{optionC}, option_d=#{optionD}, answer=#{answer}, analysis=#{analysis}
where id=#{id}
